@using sv_5350a9260ebd48768c4cb29687d8dce2

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_5350a9260ebd48768c4cb29687d8dce2

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary rounded-pill">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, MoveLeftStatus!))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, MoveRightStatus!))" />
            }

            @if (showForm)
            {
                <AddTaskForm Status="@ColumnName"
                             OnSave="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public string? MoveLeftStatus { get; set; }
    [Parameter] public string? MoveRightStatus { get; set; }
    [Parameter] public EventCallback<(int taskId, string newStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string title, string assignee, string priority, DateTime dueDate, string status)> OnAddTask { get; set; }

    private bool showForm;

    private async Task HandleTaskCreated((string title, string assignee, string priority, DateTime dueDate) args)
    {
        await OnAddTask.InvokeAsync((args.title, args.assignee, args.priority, args.dueDate, ColumnName));
        showForm = false;
    }
}

@page "/board"
@using sv_5350a9260ebd48768c4cb29687d8dce2
@using sv_5350a9260ebd48768c4cb29687d8dce2.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="filteredTasks.Count"
                TodoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="filteredTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="todoTasks"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      MoveRightStatus="In Progress"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="inProgressTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      MoveLeftStatus="To Do"
                      MoveRightStatus="Done"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="Done"
                      Tasks="doneTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      MoveLeftStatus="In Progress"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private List<TaskItem> filteredTasks => allTasks
        .Where(t => string.IsNullOrEmpty(searchText) ||
                     t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
        .ToList();

    private List<TaskItem> todoTasks => filteredTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => filteredTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => filteredTasks.Where(t => t.Status == "Done").ToList();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleMoveTask((int taskId, string newStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.taskId, args.newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == args.taskId);
            if (task is not null)
            {
                var index = allTasks.IndexOf(task);
                allTasks[index] = task with { Status = args.newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleAddTask((string title, string assignee, string priority, DateTime dueDate, string status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.title, args.assignee, args.priority, args.dueDate);
            allTasks.Add(newTask with { Status = args.status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

